        let tmp = tempfile::tempdir().expect("tempdir");
        let pow_bits = 0x207f_ffff;
        let node =
            NativeNode::open(test_config(tmp.path(), pow_bits, "unsafe", false)).expect("node");
        let parent = node.best_meta();
